/* 커스텀 스타일 (Tailwind CSS 보완용) */

/* 필터 버튼 활성화 스타일 */
.filter-btn {
    background-color: #f3f4f6;
    color: #6b7280;
}

.filter-btn:hover {
    background-color: #e5e7eb;
}

.filter-btn.active {
    background-color: #3b82f6;
    color: white;
}

/* 버킷 리스트 항목 애니메이션 */
.bucket-item {
    animation: slideIn 0.3s ease-out;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

/* 완료된 항목 스타일 */
.bucket-item .line-through {
    text-decoration: line-through;
    opacity: 0.6;
}

/* 체크박스 호버 효과 */
.bucket-item button:first-child:hover {
    transform: scale(1.1);
}

/* 스크롤바 스타일 (Chrome, Safari) */
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: #f1f1f1;
}

::-webkit-scrollbar-thumb {
    background: #888;
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: #555;
}

/* 모바일 반응형 */
@media (max-width: 640px) {
    .bucket-item {
        flex-direction: column;
        align-items: flex-start;
    }

    .bucket-item > div:last-child {
        width: 100%;
        justify-content: flex-end;
        margin-top: 8px;
    }

    .filter-btn {
        font-size: 0.875rem;
        padding: 0.5rem 1rem;
    }
}

/* 입력 필드 포커스 효과 */
input:focus {
    box-shadow: 0 0 0 3px rgba(59, 130, 246, 0.1);
}

/* 버튼 클릭 효과 */
button:active {
    transform: scale(0.98);
}

/* 빈 상태 메시지 애니메이션 */
#emptyState {
    animation: fadeIn 0.5s ease-in;
}

@keyframes fadeIn {
    from {
        opacity: 0;
    }
    to {
        opacity: 1;
    }
}

/* 모달 백드롭 애니메이션 */
#editModal {
    animation: fadeIn 0.2s ease-in;
}

#editModal > div {
    animation: scaleIn 0.2s ease-out;
}

@keyframes scaleIn {
    from {
        opacity: 0;
        transform: scale(0.95);
    }
    to {
        opacity: 1;
        transform: scale(1);
    }
}

/* 통계 숫자 애니메이션 */
#totalCount, #completedCount, #progressCount, #completionRate {
    transition: all 0.3s ease;
}

/* 다크 모드 지원 (선택사항) */
@media (prefers-color-scheme: dark) {
    body {
        background-color: #1f2937;
    }

    .bg-white {
        background-color: #374151;
    }

    .text-gray-800 {
        color: #f3f4f6;
    }

    .text-gray-600 {
        color: #d1d5db;
    }

    .border-gray-300 {
        border-color: #4b5563;
    }
}
